diff --git a/Dapper/SqlMapper.cs b/Dapper/SqlMapper.cs
index d23e949..ead427e 100644
--- a/Dapper/SqlMapper.cs
+++ b/Dapper/SqlMapper.cs
@@ -2991,7 +2991,27 @@ private static int ExecuteCommand(IDbConnection cnn, ref CommandDefinition comma
             {
                 cmd = command.SetupCommand(cnn, paramReader);
                 if (wasClosed) cnn.Open();
-                int result = cmd.ExecuteNonQuery();
+                int result;
+                // For stored procedures, ExecuteNonQuery returns -1 when the procedure contains
+                // DML statements without SET NOCOUNT ON. Use a reader to aggregate all row counts.
+                if (command.CommandTypeDirect == CommandType.StoredProcedure)
+                {
+                    result = 0;
+                    using var reader = cmd.ExecuteReader();
+                    do
+                    {
+                        int n = reader.RecordsAffected;
+                        if (n >= 0) result += n;
+                    }
+                    while (reader.NextResult());
+                    // Pick up any final RecordsAffected after all result sets are consumed
+                    int last = reader.RecordsAffected;
+                    if (last >= 0) result += last;
+                }
+                else
+                {
+                    result = cmd.ExecuteNonQuery();
+                }
                 command.OnCompleted();
                 return result;
             }
